-- 担当者別成績管理テーブル作成マイグレーション
-- 作成日：2026-06-03

CREATE TABLE IF NOT EXISTS sales_targets (
    id            INTEGER PRIMARY KEY AUTOINCREMENT,
    agency_code   TEXT NOT NULL,
    staff_code    TEXT NOT NULL,
    fiscal_year   INTEGER NOT NULL,
    month         INTEGER NOT NULL,
    policy_type   TEXT NOT NULL,
    target_amount INTEGER,
    created_at    TEXT DEFAULT (datetime('now','localtime')),
    updated_at    TEXT DEFAULT (datetime('now','localtime')),
    UNIQUE(agency_code, staff_code, fiscal_year, month, policy_type)
);

-- ダミーデータ：A001代理店 2025年度・2026年度
-- staff_code: admin / staff1 / ALL（代理店合計）
-- policy_type: AUTO / FIRE / INJURY / JIBAI / LIABILITY / CYBER / INCOME / TOTAL
-- 月は4〜3（年度順）

